#include <bits/stdc++.h>
using namespace std;

int n, sum, ans, a[1000005];

void DFS(int p, int s, int t) {
    if (t >= 500010) {
        cout << 0;
        exit(0);
    }
    if (p > 2) {
        if ((sum - ans) % 10 == 0) {
            if (ans % 10) 
                cout << ans % 10;
            else
                cout << 10;
            exit(0);
        }
        return ;
    }
    for (int i = s; i <= n; i++) {
        ans += a[i];
        DFS(p + 1, s + 1, ++t);
        ans -= a[i];
    }
}

int main() {
    cin >> n;
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
        sum += a[i];
    }
    DFS(1, 1, 0);
    cout << 0;
    return 0;
}
